import React, { useEffect, createContext, useContext } from 'react';
import Lenis from '@studio-freight/lenis';
import { useLocation } from 'react-router-dom';

const LenisContext = createContext(null);

export function useLenis() {
  return useContext(LenisContext);
}

export function SmoothScroll({ children }) {
  const [lenis, setLenis] = React.useState(null);
  const location = useLocation();

  // Initialize Lenis
  useEffect(() => {
    if (typeof window === 'undefined') return;
    let localLenis;
    try {
      localLenis = new Lenis({
        duration: 1.2,
        easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
        smoothTouch: false,
        touchMultiplier: 2,
        infinite: false,
      });

      setLenis(localLenis);

      function raf(time) {
        localLenis.raf(time);
        requestAnimationFrame(raf);
      }
      requestAnimationFrame(raf);
    } catch (err) {
      console.error('[SmoothScroll] Lenis Init Error:', err);
    }

    return () => {
      if (localLenis) localLenis.destroy();
    };
  }, []);

  // Handle route changes
  useEffect(() => {
    if (lenis) {
      lenis.scrollTo(0, { immediate: true });
    }
  }, [location.pathname, lenis]);

  // Hero Conflict Resolution
  useEffect(() => {
    if (typeof window === 'undefined') return;
    const heroEl = document.getElementById('hero-section');
    if (!heroEl || !lenis) return;

    let heroObserver;
    try {
      heroObserver = new IntersectionObserver(
        ([entry]) => {
          if (entry.isIntersecting) {
            lenis.stop();
          } else {
            lenis.start();
          }
        },
        { threshold: 0.05 }
      );
      heroObserver.observe(heroEl);
    } catch (err) {
      console.error('[SmoothScroll] Hero Observer Error:', err);
    }

    return () => {
      if (heroObserver) heroObserver.disconnect();
    };
  }, [lenis]);

  if (typeof window === 'undefined') return <>{children}</>;

  return (
    <LenisContext.Provider value={lenis}>
      {children}
    </LenisContext.Provider>
  );
}

export default SmoothScroll;

