          style={{ x: cursorX, y: cursorY }}
          className="pointer-events-none fixed left-0 top-0 z-50 hidden md:block"
        >
          <AnimatePresence mode="wait">
            {activeId && (
              <motion.div
                initial={{ opacity: 0, scale: 0.5, filter: 'blur(10px)' }}
                animate={{ opacity: 1, scale: 1, filter: 'blur(0px)' }}
                exit={{ opacity: 0, scale: 0.5, filter: 'blur(10px)' }}
                transition={{ type: 'spring', stiffness: 300, damping: 25 }}
                className="relative h-64 w-80 overflow-hidden rounded-xl border border-primary/20 bg-[var(--bg-card)] shadow-2xl"
              >
                <img
                  src={TEAM.find((t) => t.id === activeId)?.image}
                  alt="Preview"
                  className="h-full w-full object-cover"
                />

                {/* Overlay Metadata */}
                <div className="absolute bottom-0 w-full bg-gradient-to-t from-black/80 to-transparent p-4">
                  <div className="flex items-center gap-2">
                    <div className="h-1.5 w-1.5 rounded-full bg-green-500 animate-pulse" />
                    <span className="text-caption uppercase tracking-widest text-[var(--text-muted)]">
                      {TEAM.find((t) => t.id === activeId)?.role}
                    </span>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </motion.div>
      )}
    </div>
  );
}

/* ---------- Row Component ---------- */

function TeamRow({ data, index, isActive, setActiveId, isMobile, isAnyActive }) {
  const isDimmed = isAnyActive && !isActive;

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 20 }}
      whileInView={{
        opacity: isDimmed ? 0.3 : 1,
        y: 0,
      }}
      animate={{
        opacity: isDimmed ? 0.3 : 1,
        backgroundColor: isActive && isMobile ? 'rgba(167, 63, 208, 0.05)' : 'transparent',
      }}
      viewport={{ once: true }}
      transition={{ duration: 0.4, delay: index * 0.05 }}
      onMouseEnter={() => !isMobile && setActiveId(data.id)}
      onMouseLeave={() => !isMobile && setActiveId(null)}
      onClick={() => isMobile && setActiveId(isActive ? null : data.id)}
      className={`group relative border-t border-[var(--border-color)] transition-colors duration-500 last:border-b ${
        isMobile ? 'cursor-pointer' : 'cursor-default'
      }`}
    >
      <div className="relative z-10 flex flex-col py-6 md:flex-row md:items-center md:justify-between md:py-8">
        {/* Name & Index */}
        <div className="flex items-baseline gap-6 md:gap-12 pl-4 md:pl-0 transition-transform duration-500 group-hover:translate-x-4">
          <span className="font-mono text-caption text-[var(--text-muted)]">
            {data.id}
          </span>
          <h3 className="heading-sm font-semibold tracking-tight text-[var(--text-muted)] transition-colors duration-300 group-hover:text-[var(--text-heading)]">
            {data.name}
          </h3>
        </div>

        {/* Role & Icon */}
        <div className="mt-4 flex items-center justify-between pl-12 pr-4 md:mt-0 md:justify-end md:gap-12 md:pl-0 md:pr-0">
          <span className="text-caption sm:text-xs font-bold uppercase tracking-[0.2em] text-[var(--text-muted)] transition-colors group-hover:text-primary">
            {data.role}
          </span>

          {/* Mobile Toggle Icon */}
          <div className="block md:hidden text-[var(--text-muted)]">
            {isActive ? <Minus size={18} /> : <Plus size={18} />}
          </div>

          {/* Desktop Arrow */}
          <motion.div
            animate={{ x: isActive ? 0 : -10, opacity: isActive ? 1 : 0 }}
            className="hidden md:block text-primary"
          >
            <ArrowUpRight size={28} strokeWidth={1.5} />
          </motion.div>
        </div>
      </div>

      {/* MOBILE ONLY: Inline Accordion */}
      <AnimatePresence>
        {isMobile && isActive && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.3, ease: 'easeInOut' }}
            className="overflow-hidden"
          >
            <div className="p-4 pb-8">
              <div className="flex gap-4 items-start">
                <div className="relative shrink-0 w-20 h-20 rounded-xl overflow-hidden">
                  <img
                    src={data.image}
                    alt={data.name}
                    className="h-full w-full object-cover"
                  />
                </div>
                <div className="flex-1">
                  <p className="text-small text-body mb-3">
                    {data.bio}
                  </p>
                  <div className="flex flex-wrap gap-1.5">
                    {data.expertise.map((skill, i) => (
                      <span
                        key={i}
                        className="px-2 py-0.5 bg-primary/10 text-primary text-caption font-bold uppercase tracking-wider rounded-md border border-primary/20"
                      >
                        {skill}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

'use client';

import React from 'react';
import {
  motion,
  AnimatePresence,
} from 'framer-motion';
import { Plus, Loader2 } from 'lucide-react';
import { cn } from '../../lib/utils';

/**
 * A micro-interaction button that expands from a circular icon to a pill shape
 * containing text upon hover. It handles loading states by reverting to the
 * circular shape and displaying a spinner.
 */
const MicroExpander = React.forwardRef(
  (
    {
      text,
      icon,
      variant = 'default',
      isLoading = false,
      className,
      onClick,
      ...props
    },
    ref
  ) => {
    const [isHovered, setIsHovered] = React.useState(false);

    const containerVariants = {
      initial: { width: '48px' },
      hover: { width: 'auto' },
      loading: { width: '48px' },
    };

    const textVariants = {
      initial: { opacity: 0, x: -10 },
      hover: {
        opacity: 1,
        x: 0,
        transition: { delay: 0.15, duration: 0.3, ease: 'easeOut' },
      },
      exit: {
        opacity: 0,
        x: -5,
        transition: { duration: 0.1, ease: 'linear' },
      },
    };

    const variantStyles = {
      default: 'bg-primary text-primary-foreground border border-primary',
      outline:
        'bg-transparent border border-input text-foreground hover:border-primary',
      ghost:
        'bg-accent/50 border border-transparent text-accent-foreground hover:bg-accent',
      destructive:
        'bg-destructive text-destructive-foreground border border-destructive hover:bg-destructive/90',
    };

    const handleClick = (e) => {
      if (isLoading) return;
      onClick?.(e);
    };

    return (
      <motion.button
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        ref={ref}
        className={cn(
          'relative flex h-12 items-center rounded-full transition-all duration-300', // Use standard CSS transition for background/border
          'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2',
          isLoading && 'cursor-not-allowed',
          variantStyles[variant],
          className
        )}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        onFocus={() => setIsHovered(true)}
        onBlur={() => setIsHovered(false)}
        onClick={handleClick}
        disabled={isLoading}
        {...props}
        aria-label={text}
      >
        <div className='grid h-12 w-12 place-items-center shrink-0 z-10'>
          <AnimatePresence mode='popLayout'>
            {isLoading ? (
              <motion.div
                key='spinner'
                initial={{ opacity: 0, scale: 0.5, rotate: -90 }}
                animate={{ opacity: 1, scale: 1, rotate: 0 }}
                exit={{ opacity: 0, scale: 0.5 }}
                transition={{ duration: 0.2 }}
              >
                <Loader2 className='h-5 w-5 animate-spin' />
              </motion.div>
            ) : (
              <motion.div
                key='icon'
                initial={{ opacity: 0, scale: 0.5 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.5 }}
                transition={{ duration: 0.2 }}
              >
                {icon || <Plus className='h-5 w-5' />}
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <motion.div
          initial={{ width: 0, opacity: 0 }}
          animate={{ 
            width: isHovered && !isLoading ? 'auto' : 0, 
            opacity: isHovered && !isLoading ? 1 : 0 
          }}
          transition={{ 
            type:"spring", 
            stiffness: 500, 
            damping: 30, 
            mass: 0.5 
          }}
          className='overflow-hidden'
        >
          <div className='whitespace-nowrap font-medium text-small uppercase tracking-wide pr-6 pl-0'>
            {text}
          </div>
        </motion.div>
      </motion.button>
    );
  }
);

MicroExpander.displayName = 'MicroExpander';

export { MicroExpander };

import React, { forwardRef } from"react";
import { motion } from"framer-motion";
import { cn } from"../../lib/utils"; 

const ServiceGrid = forwardRef(({ title, subtitle, services, className, ...props }, ref) => {
  // Animation variants for the container to orchestrate children animations
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1, // Stagger the animation of children by 0.1s
      },
    },
  };

  // Animation variants for each grid item
  const itemVariants = {
    hidden: { y: 20, opacity: 0 },
    visible: {
      y: 0,
      opacity: 1,
      transition: {
        type:"spring",
        stiffness: 100,
        damping: 10,
      },
    },
  };

  return (
    <section
      ref={ref}
      className={cn("w-full py-12 md:py-16 lg:py-20", className)}
      {...props}
    >
      <div className="container-custom">
        {/* Header Section */}
        <div className="flex flex-col items-center justify-center space-y-4 text-center mb-12 md:mb-16">
          <div className="space-y-4 max-w-4xl mx-auto">
            <h2 className="heading-lg font-semibold text-[var(--text-heading)]">
              {title}
            </h2>
            {subtitle && (
              <p className="text-[var(--text-muted)] text-body-lg md:text-xl leading-relaxed">
                {subtitle}
              </p>
            )}
          </div>
        </div>

        {/* Animated Grid Section */}
        <motion.div
          className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4 sm:gap-6 md:gap-8"
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin:"-100px" }}
        >
          {services.map((service, index) => (
            <motion.div
              key={index}
              className="group flex flex-col items-center justify-start gap-4 text-center p-6 rounded-3xl bg-[var(--bg-card)] border border-[var(--border-color)] shadow-sm cursor-default"
              variants={itemVariants}
              whileHover={{ scale: 1.05, y: -8 }} // Hover animation
              transition={{ type:"spring", stiffness: 300, damping: 15 }}
            >
              <div className="flex items-center justify-center w-16 h-16 sm:w-20 sm:h-20 rounded-2xl bg-primary/5 mb-2 group-hover:bg-primary/10 transition-colors">
                <img
                  src={service.imageUrl}
                  alt={`${service.name} skill icon`}
                  width={48}
                  height={48}
                  className="object-contain rounded-md transition-transform duration-300 group-hover:scale-110 drop-shadow-sm"
                />
              </div>
              
              <div className="flex flex-col gap-1 items-center">
                <span className="text-body sm:text-lg font-bold text-[var(--text-heading)] transition-colors duration-300 group-hover:text-primary">
                  {service.name}
                </span>
                
                {/* Custom Demand Pill */}
                {service.demand && (
                  <span className={`text-caption font-black uppercase tracking-widest px-2.5 py-1 rounded-full border mt-1 ${
                    service.demand === 'Critical' ? 'bg-red-500/10 text-red-500 border-red-500/20' :
                    service.demand === 'Very High' ? 'bg-orange-500/10 text-orange-500 border-orange-500/20' :
                    service.demand === 'High' ? 'bg-yellow-500/10 text-yellow-500 border-yellow-500/20' :
                    service.demand === 'Growing' ? 'bg-green-500/10 text-green-500 border-green-500/20' :
                    'bg-blue-500/10 text-blue-500 border-blue-500/20'
                  }`}>
                    {service.demand}
                  </span>
                )}
              </div>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </section>
  );
});

ServiceGrid.displayName ="ServiceGrid";

export { ServiceGrid };

