      <div className="bg-[var(--bg-secondary)] py-20">
        <div className="container-custom">

          {/* Summary stats */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-12">
            {sections.map((s) => (
              <div
                key={s.title}
                className="bg-[var(--bg-card)] rounded-2xl p-5 border border-[var(--border-color)] flex items-center gap-4"
              >
                <div className={`p-3 rounded-xl bg-gradient-to-br ${s.color}`}>
                  <s.icon className="h-5 w-5 text-white" />
                </div>
                <div>
                  <p className="heading-md font-black text-[var(--text-heading)]">{s.links.length}</p>
                  <p className="text-caption font-bold text-[var(--text-muted)] leading-tight">{s.title}</p>
