            <div className="flex flex-col sm:flex-row gap-3 justify-center">
              <Link
                to="/contact"
                className="px-6 py-3 bg-[var(--bg-inverted)] text-[var(--text-on-light)] font-bold rounded-xl hover:opacity-90 transition-all text-small"
